// Each entry names the env vars holding that class's own credentials, the
// endpoint that exercises it, and whether DCS is expected to permit it.
var probes = [
    { role: 'Sys. Contract Creator', idEnv: 'ORCE_CREATOR_CLIENT_ID', secretEnv: 'ORCE_CREATOR_CLIENT_SECRET', method: 'GET',  path: '/template/search', expect: 'allowed' },
    { role: 'Sys. Contract Manager', idEnv: 'ORCE_MANAGER_CLIENT_ID', secretEnv: 'ORCE_MANAGER_CLIENT_SECRET', method: 'GET',  path: '/contract/retrieve', expect: 'allowed' },
    { role: 'Sys. Contract Signer',  idEnv: 'ORCE_SIGNER_CLIENT_ID',  secretEnv: 'ORCE_SIGNER_CLIENT_SECRET',  method: 'POST', path: '/signature/request', expect: 'refused' }
];

var out = [];
for (var i = 0; i < probes.length; i++) {
    var probe = probes[i];
    var clientId = env.get(probe.idEnv);
    var clientSecret = env.get(probe.secretEnv);
    if (!clientId || !clientSecret) {
        node.warn(probe.role + ' has no credentials configured (' + probe.idEnv + '), skipping');
        continue;
    }
    out.push({ probe: probe, clientId: clientId, clientSecret: clientSecret });
}
return [out];

var TOKEN_URL = env.get('HYDRA_TOKEN_URL');
if (!TOKEN_URL) {
    node.error('HYDRA_TOKEN_URL is not configured', msg);
    return null;
}

msg.probe = msg.payload.probe;
msg.url = TOKEN_URL;
msg.method = 'POST';
msg.headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
msg.payload = 'grant_type=client_credentials'
    + '&client_id=' + encodeURIComponent(msg.payload.clientId)
    + '&client_secret=' + encodeURIComponent(msg.payload.clientSecret);
return msg;

if (msg.statusCode !== 200 || !msg.payload || !msg.payload.access_token) {
    node.error(msg.probe.role + ': Hydra refused the client_credentials grant: HTTP ' + msg.statusCode, msg);
    return null;
}

var DCS_URL = env.get('DCS_URL');
if (!DCS_URL) {
    node.error('DCS_URL is not configured', msg);
    return null;
}

msg.method = msg.probe.method;
msg.url = DCS_URL.replace(/\/$/, '') + msg.probe.path;
msg.headers = {
    'Authorization': 'Bearer ' + msg.payload.access_token,
    'Content-Type': 'application/json'
};
msg.payload = msg.probe.method === 'POST' ? {} : '';
return msg;

var probe = msg.probe;
var status = msg.statusCode;
var refused = (status === 401 || status === 403);

var result = {
    role: probe.role,
    call: probe.method + ' ' + probe.path,
    status: status,
    expected: probe.expect
};

if (probe.expect === 'refused') {
    if (refused) {
        result.verdict = 'OK - refused, as eIDAS requires (ADR-17)';
        return [result, null];
    }
    // A machine that CAN sign is a compliance defect, not a happy path.
    result.verdict = 'COMPLIANCE DEFECT - a System Contract Signer was allowed to sign';
    node.error(result.verdict + ': HTTP ' + status, msg);
    return [null, { payload: result }];
}

if (refused) {
    result.verdict = 'DENIED - is this client listed under systemClients in the DCS values?';
    return [null, { payload: result }];
}
result.verdict = 'OK - permitted';
return [{ payload: result }, null];
